import{_ as l,c as i,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI工具/rowboat-AI工具.md","filePath":"github汇总/AI工具/rowboat-AI工具.md"}'),o={name:"github汇总/AI工具/rowboat-AI工具.md"};function t(s,a,h,n,d,b){return e(),i("div",null,a[0]||(a[0]=[r(`<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>Rowboat</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>Rowboat Labs</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>AI工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>工作中需要处理大量的电子邮件和会议笔记，难以保持对重要信息的记忆和理解，需要一个能够帮助整理和利用这些信息的工具。</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>连接到电子邮件和会议笔记，构建长期知识图谱</li><li>生成基于知识图谱的演示文稿、会议简报等</li><li>可视化、编辑和更新知识图谱</li><li>录制语音备忘录，自动捕获和更新知识图谱中的关键要点</li><li>支持本地模型和托管模型</li><li>通过Model Context Protocol (MCP)连接到外部工具和服务</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>本地优先设计，所有数据以纯Markdown格式存储在用户机器上</li><li>没有专有格式或托管锁定，用户可以随时检查、编辑、备份或删除所有内容</li><li>支持多种模型，包括本地模型和托管模型</li><li>可以通过MCP连接到外部工具和服务</li><li>背景代理可以自动执行重复性工作</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/rowboatlabs/rowboat" target="_blank" rel="noreferrer">https://github.com/rowboatlabs/rowboat</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于需要在工作中管理大量信息和提高工作效率的用户，支持Mac、Windows和Linux系统。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li>系统要求：Mac、Windows或Linux</li><li>依赖：无特殊依赖</li><li>权限要求：有足够的权限安装软件</li></ol><h2 id="主路径-安装与启动" tabindex="-1">主路径：安装与启动 <a class="header-anchor" href="#主路径-安装与启动" aria-label="Permalink to “主路径：安装与启动”">​</a></h2><h3 id="下载安装" tabindex="-1">下载安装 <a class="header-anchor" href="#下载安装" aria-label="Permalink to “下载安装”">​</a></h3><ol><li><p><strong>下载最新版本</strong></p><ul><li>执行位置：浏览器</li><li>操作：访问 <a href="https://github.com/rowboatlabs/rowboat/releases/latest" target="_blank" rel="noreferrer">https://github.com/rowboatlabs/rowboat/releases/latest</a> 下载对应系统的安装包</li><li>成功标志：下载完成，获得安装包</li><li>失败处理：检查网络连接</li></ul></li><li><p><strong>安装软件</strong></p><ul><li>执行位置：本地</li><li>操作：运行下载的安装包，按照提示完成安装</li><li>成功标志：安装完成，软件可以启动</li><li>失败处理：检查系统权限，确保有足够的权限安装软件</li></ul></li></ol><h3 id="google设置" tabindex="-1">Google设置 <a class="header-anchor" href="#google设置" aria-label="Permalink to “Google设置”">​</a></h3><ol><li><strong>连接Google服务</strong><ul><li>执行位置：Rowboat应用</li><li>操作：按照Google设置指南连接Gmail、Calendar和Drive</li><li>成功标志：Google服务连接成功</li><li>失败处理：检查Google账户权限</li></ul></li></ol><h3 id="语音笔记设置" tabindex="-1">语音笔记设置 <a class="header-anchor" href="#语音笔记设置" aria-label="Permalink to “语音笔记设置”">​</a></h3><ol><li><strong>添加Deepgram API密钥</strong><ul><li>执行位置：本地</li><li>操作：在 ~/.rowboat/config/deepgram.json 文件中添加Deepgram API密钥<div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;apiKey&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;key&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li><li>成功标志：文件创建成功</li><li>失败处理：检查文件路径是否正确</li></ul></li></ol><h3 id="网络搜索设置" tabindex="-1">网络搜索设置 <a class="header-anchor" href="#网络搜索设置" aria-label="Permalink to “网络搜索设置”">​</a></h3><ol><li><p><strong>添加Brave搜索API密钥</strong></p><ul><li>执行位置：本地</li><li>操作：在 ~/.rowboat/config/brave-search.json 文件中添加Brave API密钥</li><li>成功标志：文件创建成功</li><li>失败处理：检查文件路径是否正确</li></ul></li><li><p><strong>添加Exa研究搜索API密钥</strong></p><ul><li>执行位置：本地</li><li>操作：在 ~/.rowboat/config/exa-search.json 文件中添加Exa API密钥</li><li>成功标志：文件创建成功</li><li>失败处理：检查文件路径是否正确</li></ul></li></ol><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><ul><li>执行操作：启动Rowboat应用</li><li>预期返回：应用启动成功，显示主界面</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>Google服务连接失败</strong></p><ul><li>现象：无法连接Gmail、Calendar或Drive</li><li>可能原因：Google账户权限不足、网络连接问题</li><li>解决步骤：检查Google账户权限，确保网络连接正常</li></ul></li><li><p><strong>语音笔记功能无法使用</strong></p><ul><li>现象：无法录制语音备忘录</li><li>可能原因：Deepgram API密钥未正确配置</li><li>解决步骤：检查Deepgram API密钥是否正确配置</li></ul></li><li><p><strong>网络搜索功能无法使用</strong></p><ul><li>现象：无法使用Brave或Exa搜索</li><li>可能原因：API密钥未正确配置</li><li>解决步骤：检查API密钥是否正确配置</li></ul></li></ol><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><p>README/仓库信息中未提供其他部署方式。</p><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>README/仓库信息中未提供完整的模型配置教程，上述教程基于README中提到的安装方式整理。</p>`,38)]))}const g=l(o,[["render",t]]);export{p as __pageData,g as default};
